create extension if not exists pgcrypto;
create table if not exists public.projects(id uuid primary key default gen_random_uuid(),code text unique not null,name text not null,client text,status text default 'active',created_at timestamptz default now());
create table if not exists public.activities(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,code text not null,name text not null,zone text,responsible text,start_date date,finish_date date,progress numeric(5,2) default 0 check(progress between 0 and 100),status text default 'not_started',critical boolean default false,created_at timestamptz default now(),unique(project_id,code));
create table if not exists public.documents(id uuid primary key default gen_random_uuid(),project_id uuid not null references public.projects(id) on delete cascade,title text not null,reference text,revision text,status text default 'draft',created_at timestamptz default now());
alter table public.projects enable row level security; alter table public.activities enable row level security; alter table public.documents enable row level security;
drop policy if exists "authenticated manage projects" on public.projects; create policy "authenticated manage projects" on public.projects for all to authenticated using(true) with check(true);
drop policy if exists "authenticated manage activities" on public.activities; create policy "authenticated manage activities" on public.activities for all to authenticated using(true) with check(true);
drop policy if exists "authenticated manage documents" on public.documents; create policy "authenticated manage documents" on public.documents for all to authenticated using(true) with check(true);
insert into public.projects(code,name,client) values('PDD','PDD','ONCF') on conflict(code) do nothing;
with p as(select id from public.projects where code='PDD' limit 1) insert into public.activities(project_id,code,name,zone,responsible,start_date,finish_date,progress,status,critical) select p.id,s.code,s.name,s.zone,s.responsible,current_date+s.ds,current_date+s.df,s.progress,s.status,s.critical from p cross join (values('ACT-001','Validation des données d’entrée','Casa-Port','Ayoub',0,1,75,'in_progress',true),('ACT-002','Petit génie civil — artère câble','Triangle','Avanzit',1,5,35,'in_progress',false),('ACT-003','Pose PEHD et TPC','Casa-Port','Avanzit',4,10,10,'not_started',true),('ACT-004','Réalisation circuit MALT','Triangle','Haj',7,12,0,'not_started',false),('ACT-005','Pose portique et potence','Casa-Port','Haj',11,17,0,'not_started',true)) as s(code,name,zone,responsible,ds,df,progress,status,critical) where not exists(select 1 from public.activities a where a.project_id=p.id and a.code=s.code);
with p as(select id from public.projects where code='PDD' limit 1) insert into public.documents(project_id,title,reference,revision,status) select p.id,s.title,s.reference,s.revision,s.status from p cross join(values('Plan technique Casa-Port','PT-CP-001','04','approved'),('Procédure petit génie civil','SI1-T-EF-ACA-PRQ-0001','02','under_review'),('Plan de pose Triangle','PP-TRI-001','01','draft')) as s(title,reference,revision,status) where not exists(select 1 from public.documents d where d.project_id=p.id and d.reference=s.reference);
